<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{Task,TaskChecklist};use App\Support\CurrentWorkspace;use Illuminate\Http\Request;
class TaskChecklistController extends Controller{use Concerns;public function store(Request $r,Task $task,CurrentWorkspace $cw){$this->requirePerm('tenant.tasks.update');$w=$this->ws($cw);$d=$r->validate(['title'=>'required|string|max:255']);$task->checklistItems()->create(['workspace_id'=>$w->id]+$d);$this->logTask($task,'checklist_added',[],['title'=>$d['title']]);return back();}public function update(Request $r,Task $task,TaskChecklist $checklist){$this->requirePerm('tenant.tasks.update');abort_unless($checklist->task_id===$task->id,404);$done=$r->boolean('is_completed');$checklist->update(['is_completed'=>$done,'completed_by'=>$done?$r->user()->id:null,'completed_at'=>$done?now():null]);$this->logTask($task,'checklist_updated',[],['id'=>$checklist->id,'is_completed'=>$done]);return back();}public function destroy(Task $task,TaskChecklist $checklist){$this->requirePerm('tenant.tasks.update');abort_unless($checklist->task_id===$task->id,404);$checklist->delete();$this->logTask($task,'checklist_deleted',['id'=>$checklist->id],[]);return back();}}
